import { QueryClient } from '@tanstack/react-query';

import { getCurrentUserDetails } from '@dynatrace-sdk/app-environment';
import {
  filterSegmentsClient,
  type FilterSegment,
  type DetailedFilterSegment,
} from '@dynatrace-sdk/client-filter-segment-management';

/**
 * React-query's queryClient to coordinate queries.
 * @internal
 */
const segmentQueryClient = new QueryClient({
  defaultOptions: {
    queries: {
      refetchOnWindowFocus: false,
      refetchOnMount: true,
      retry: false,
      staleTime: Infinity,
    },
  },
});

export type CachedSegment = {
  segment: Omit<DetailedFilterSegment | FilterSegment, 'uid'> & { id: string };
  temporarilyApplied: boolean;
};

const currentUser = getCurrentUserDetails();

function catchError(error: Error) {
  if (error.name === '403' || error.message === '403') {
    segmentsClient.hasAccessRights = false;
    segmentsClient.queryClient.setDefaultOptions({
      queries: { enabled: false },
    });
  }
}

function getSegmentFromCache(id: string): CachedSegment | null {
  const allSegments = segmentsClient.queryClient.getQueryData<
    Map<string, CachedSegment>
  >(['getAllSegments']);
  const singleSegment = segmentsClient.queryClient.getQueryData<CachedSegment>([
    'getSegment',
    id,
  ]);

  return allSegments?.get(id) ?? singleSegment ?? null;
}

/**
 * @internal
 */
export const segmentsClient: {
  queryClient: QueryClient;
  hasAccessRights: boolean | undefined;
} = {
  /** react-query's queryClient used for segments queries. */
  queryClient: segmentQueryClient,
  /** flag for missing access rights (403) for any segments query. */
  hasAccessRights: undefined,
};

function processSegment(
  segment: DetailedFilterSegment | FilterSegment,
): CachedSegment {
  const { uid, ...remainingSegment } = segment;

  return {
    segment: { ...remainingSegment, id: uid },
    temporarilyApplied: !(segment.isPublic || segment.owner === currentUser.id),
  };
}

/**
 * Returns a Promise<CachedSegment>.
 * @internal
 */
export async function getSegment(uid?: string): Promise<CachedSegment> {
  if (!uid) {
    throw new Error('Segment id is required');
  }

  if (segmentsClient.hasAccessRights === false) {
    throw new Error('403');
  }

  // Currently all data is up to date and not invalidated, so we can return the cached segment directly.
  if (
    segmentsClient.queryClient.isFetching({ queryKey: ['getAllSegments'] }) ===
      0 &&
    !segmentsClient.queryClient.getQueryState<Map<string, CachedSegment>>([
      'getAllSegments',
    ])?.isInvalidated
  ) {
    const cachedSegment = getSegmentFromCache(uid);
    if (cachedSegment) {
      return cachedSegment;
    }
  }

  return new Promise<CachedSegment>((resolve, reject) => {
    filterSegmentsClient
      .getFilterSegment({
        filterSegmentUid: uid,
        addFields: ['VARIABLES'],
      })
      .then((storeSegment) => {
        const newCachedSegment = processSegment(storeSegment);
        segmentsClient.hasAccessRights = true;
        resolve(newCachedSegment);
      })
      .catch((error: Error) => {
        catchError(error);
        reject(error);
        return null;
      });
  });
}

/**
 * Returns a Promise for all Cached Segments.
 * @internal
 */
async function getAllSegments() {
  if (segmentsClient.hasAccessRights === false) {
    throw new Error('403');
  }

  return new Promise<Map<string, CachedSegment>>((resolve, reject) => {
    filterSegmentsClient
      .getFilterSegments({
        addFields: ['VARIABLES'],
      })
      .then((segments) => {
        const updatedCache = new Map();
        segments.filterSegments.forEach((storeSegment) => {
          const newCachedSegment = processSegment(storeSegment);
          updatedCache.set(storeSegment.uid, newCachedSegment);
          segmentsClient.hasAccessRights = true;
        });

        resolve(updatedCache);
      })
      .catch((error: Error) => {
        catchError(error);
        reject(error);
      });
  });
}

/**
 * Hook to access cached segments.
 * @internal
 * @returns
 */
export function useSegmentsCache() {
  return {
    getAllSegments,
    getSegment,
  };
}
